sys_script.script:
// Check if this is a renewal request
var catItem = current.cat_item.toString();
if (catItem && current.cat_item.name && current.cat_item.name.toString().indexOf('Policy Renewal Request') > -1) {

    // Get catalog item variables
    var variables = {};
    var variableGR = new GlideRecord('sc_item_option_mtom');
    variableGR.addQuery('request_item', current.getUniqueValue());
    variableGR.query();

    while (variableGR.next()) {
        var varName = variableGR.sc_item_option.name.toString();
        var varValue = variableGR.getValue('value');
        variables[varName] = varValue;
    }

    // Find the client by policy number
    var clientRef = '';
    if (variables.policy_number) {
        var policyGR = new GlideRecord('x_1945663_insuranc_u_insurance_clients_data');
        policyGR.addQuery('policy_number', variables.policy_number);
        policyGR.query();

        if (policyGR.next()) {
            clientRef = policyGR.getUniqueValue();
        }
    }

    if (clientRef) {
        // Create new renewal record
        var renewalGR = new GlideRecord('x_1945663_insuranc_u_renewal_data');
        renewalGR.initialize();

        renewalGR.setValue('client_reference', clientRef);

        // Set renewal date (usually policy expiry + 1 day)
        var renewalDate = new GlideDateTime(policyGR.getValue('policy_end_date'));
        renewalDate.addDaysLocalTime(1);
        renewalGR.setValue('renewal_date', renewalDate.getDisplayValue());

        renewalGR.setValue('previous_premium', policyGR.getValue('premium_amount'));
        renewalGR.setValue('new_premium', policyGR.getValue('premium_amount')); // Default to same
        renewalGR.setValue('renewal_type', 'manual');
        renewalGR.setValue('renewal_status', 'pending');
        renewalGR.setValue('renewal_period', variables.renewal_period || 'annual');
        renewalGR.setValue('agent_notes', 'Renewal requested via Service Portal. ' + 
                         (variables.coverage_changes || 'No coverage changes requested.'));

        var newRenewalId = renewalGR.insert();

        if (newRenewalId) {
            // Update the catalog request
            current.setValue('state', '3'); // Closed Complete
            current.setValue('stage', 'closed_complete');
            var workNotes = 'Renewal request processed successfully.' + 
                          '\nRenewal ID: ' + newRenewalId;
            current.setWorkNotes(workNotes);

            // Fire renewal notification event
            gs.eventQueue('insurance.renewal.status.update', renewalGR,
                         policyGR.getValue('client_name'),
                         'pending',
                         variables.email);

            gs.info('New renewal request created from catalog submission: ' + newRenewalId);
        }
    } else {
        gs.addErrorMessage('Policy number not found: ' + variables.policy_number);
    }
}
